      E("6.7", "非相对论 n<sub>eq</sub>=g(mT/2π)<sup>3/2</sup>e<sup>-m/T</sup>", "平衡丰度随 x 指数下降。"),
      E("6.8", "早期 Γ=n<sub>eq</sub>〈σv〉≫H，Y≈Y<sub>eq</sub>", "反应快，实际丰度跟随平衡丰度。"),
      E("6.9", "冻结点：n<sub>eq</sub>(x<sub>f</sub>)〈σv〉≈H(x<sub>f</sub>)", "平衡丰度低到反应跟不上膨胀。"),
      E("6.10", "冻结后 Y≫Y<sub>eq</sub>，dY/dx≈-(s〈σv〉/(Hx))Y²", "产生项可忽略，剩余粒子继续少量湮灭。"),
      E("6.11", "积分结果给 Y<sub>∞</sub>∝1/〈σv〉", "截面越大，湮灭越充分，剩余丰度越低。"),
      E("6.12", "现今 Ω<sub>χ</sub>h²∝mY<sub>∞</sub>∝1/〈σv〉", "这就是热遗迹暗物质丰度与截面反比的板书结论。")
